export function buildVoucherListToolbarActions(p) {
    const prefix = p.testIdPrefix;
    return [
        {
            id: 'refresh',
            placement: 'left',
            action: 'refresh',
            onClick: p.onRefresh,
            testId: `${prefix}-toolbar-refresh-btn`,
        },
        {
            id: 'approve',
            placement: 'left',
            action: 'approve',
            visible: p.canApprove,
            disabled: p.approveDisabled,
            onClick: p.onApprove,
            testId: `${prefix}-batch-approve-btn`,
        },
        {
            id: 'viewLedger',
            placement: 'overflow',
            action: 'viewLedger',
            visible: true,
            disabled: !p.canViewLedger,
            onClick: p.onViewLedger,
            testId: `${prefix}-toolbar-view-ledger-btn`,
        },
        {
            id: 'print',
            placement: 'overflow',
            action: 'print',
            visible: true,
            disabled: !p.canPrint,
            onClick: p.onPrint,
            testId: `${prefix}-toolbar-print-btn`,
        },
        {
            id: 'editConfig',
            placement: 'overflow',
            action: 'editConfig',
            visible: Boolean(p.onEditConfig),
            onClick: p.onEditConfig,
            testId: `${prefix}-list-config-btn`,
        },
        {
            id: 'view',
            placement: 'right',
            action: 'view',
            disabled: !p.canView,
            onClick: p.onView,
            testId: `${prefix}-toolbar-view-btn`,
        },
        {
            id: 'edit',
            placement: 'right',
            action: 'edit',
            disabled: !p.canEdit,
            onClick: p.onEdit,
            testId: `${prefix}-toolbar-edit-btn`,
        },
        {
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: p.canCreate,
            onClick: p.onCreate,
            testId: `${prefix}-toolbar-create-btn`,
        },
    ];
}
